INSERT INTO `v1_2481c5d67b2dcd3a3bd405023bc2a4b3536055a410cdbcd99a69be7e77c01c26` VALUES ("vo_minigame_1004", 1000101, 2, "vo_minigame_1004_top_1_000", 10001, 1, "ふっふっふ、これでカヤぴぃとボスを見返してやるです！");
